<template>
  <div class="homepage-container">
    <div class="hero">
      <div class="hero-content">
        <h1>47Saikyo</h1>
        <p>{{ displayedText }}<span class="cursor" :class="{ 'cursor-hidden': !showCursor }"></span></p>
      </div>
    </div>
    <AsyncHomeContent />
    
    <div class="background-container" :class="{ blurred: isScrolled }">
      <div 
        class="bg-placeholder" 
        :style="{ backgroundImage: `url(${placeholderImage})` }"
      ></div>

      <img
        class="background-image-layer"
        :class="{ 'is-loaded': isHighResLoaded }"
        :src="backgroundImage"
        alt="site background"
        @load="onHighResLoad"
      />
    </div>
  </div>
</template>

<script setup lang="ts">
import bgDark from '@/assets/bg-dark.jpg';
import bgLight from '@/assets/bg-light.jpg';
import { computed, defineAsyncComponent, ref, onMounted, onUnmounted, watch } from 'vue';

const AsyncHomeContent = defineAsyncComponent(() => import('@/component/area/homepage/HomeContent.vue'))

const isScrolled = ref(false);
const currentTheme = ref<'dark' | 'light'>('dark');
const fullText = "and in that light, I find deliverance.";
const displayedText = ref("");
const showCursor = ref(true);
let charIndex = 0;
let themeObserver: MutationObserver | null = null;

// 控制高清图是否加载完毕的开关
const isHighResLoaded = ref(false);

// 高清图片源
const backgroundImage = computed(() => (currentTheme.value === 'light' ? bgLight : bgDark));

// bg-dark和bg-light压缩到仅有10%大小的图片后转base64，作为占位图
const placeholderImage = computed(() => {
  return currentTheme.value === 'light' 
    ? 'data:image/jpeg;base64,' // 浅色占位图 (灰白)
    : 'data:image/jpeg;base64,'; // 深色占位图 (暗黑)
});
// 每次主题切换（图片源改变）时，重置加载状态
watch(backgroundImage, () => {
  isHighResLoaded.value = false;
});

// 高清图真正下载并解码完成时触发
const onHighResLoad = () => {
  isHighResLoaded.value = true;
};

const typeText = () => {
  if (charIndex < fullText.length) {
    displayedText.value += fullText.charAt(charIndex);
    charIndex++;
    setTimeout(typeText, 100);
  } else {
    setInterval(() => {
      showCursor.value = !showCursor.value;
    }, 500);
  }
};

const handleScroll = () => {
  isScrolled.value = window.scrollY > 50;
};

onMounted(() => {
  const syncTheme = () => {
    currentTheme.value = document.documentElement.getAttribute('data-theme') === 'light' ? 'light' : 'dark';
  };
  syncTheme();
  themeObserver = new MutationObserver(syncTheme);
  themeObserver.observe(document.documentElement, {
    attributes: true,
    attributeFilter: ['data-theme'],
  });
  window.addEventListener('scroll', handleScroll);
  typeText();
});

onUnmounted(() => {
  window.removeEventListener('scroll', handleScroll);
  themeObserver?.disconnect();
});
</script>

<style scoped lang="less">
.homepage-container {
  position: relative;
}

.background-container {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: var(--theme-bg);
  background-image:
    radial-gradient(circle at top, rgba(255, 255, 255, 0.12), transparent 48%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.06), rgba(0, 0, 0, 0.04));
  z-index: -1;
  overflow: hidden;
  transition: filter 0.3s ease;
  transform: scale(1.05); /* Slightly scale up to hide edges */
}

/* 占位图层：铺满，加上高斯模糊让画面变平滑 */
.bg-placeholder {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  background-size: cover;
  background-position: center;
  filter: blur(20px); /* 强模糊 */
  transform: scale(1.1); /* 防止模糊后边缘出现白边 */
  z-index: -2; 
}

/* 高清图层：默认透明度为 0 */
.background-image-layer {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover; 
  object-position: center;
  z-index: -1;
  opacity: 0;
  transition: opacity 1.2s cubic-bezier(0.4, 0, 0.2, 1); /* 优雅且缓慢的淡入动画 */
}

/* 当触发 @load 加上 is-loaded 类名后，高清图淡入 */
.background-image-layer.is-loaded {
  opacity: 1;
}

.background-container.blurred {
  filter: blur(10px);
}

.hero {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100svh;
  padding: 96px 18px 32px;
  color: var(--surface-title);
  text-align: center;
}

.hero-content {
  max-width: min(600px, 100%);

  h1 {
    font-size: clamp(2.2rem, 8vw, 4.5rem);
    line-height: 1.05;
  }

  p {
    color: var(--surface-text);
    font-size: clamp(0.98rem, 2.5vw, 1.18rem);
    line-height: 1.7;
  }

  p { display: inline; }
}

.cursor {
  display: inline-block;
  width: 2px;
  height: 1em;
  background-color: var(--surface-title);
  margin-left: 2px;
  transition: opacity 0.1s;
}

